// frontend/src/components/clients/ClientDashboard.js
import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import api from '../../services/api';
import { useAuth } from '../../contexts/AuthContext';
import ReviewModal from '../../components/jobs/ReviewModal';
import './ClientDashboard.css';
import { useNavigate } from 'react-router-dom';

const ClientDashboard = () => {
    const { user } = useAuth();
    const [jobs, setJobs] = useState({
        posted: [],
        assigned: [],
        in_progress: [],
        completed: [],
        cancelled: []
    });
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [activeTab, setActiveTab] = useState('assigned');

    // Rating modal states
    const [showRatingModal, setShowRatingModal] = useState(false);
    const [currentJobForRating, setCurrentJobForRating] = useState(null);
    const [ratingData, setRatingData] = useState({
        rating: 5,
        review: ''
    });

    // Review modal states
    const [showReviewModal, setShowReviewModal] = useState(false);
    const [currentJobForReview, setCurrentJobForReview] = useState(null);
    const [hasReviewed, setHasReviewed] = useState({});

    // Add this helper function in your component
    const calculateProgress = (status) => {
        const totalJobs = jobs.posted.length + jobs.assigned.length + 
                        jobs.in_progress.length + jobs.completed.length;

        if (totalJobs === 0) return 0;

        switch(status) {
            case 'assigned':
                return (jobs.assigned.length / totalJobs) * 100;
            case 'in_progress':
                return (jobs.in_progress.length / totalJobs) * 100;
            case 'posted':
                return (jobs.posted.length / totalJobs) * 100;
            case 'completed':
                return (jobs.completed.length / totalJobs) * 100;
            default:
                return 0;
        }
    };

    // Safe number formatting helper
    const formatRating = (rating) => {
        if (rating === null || rating === undefined) return 'New';
        const numRating = Number(rating);
        return isNaN(numRating) ? 'New' : numRating.toFixed(1);
    };

    useEffect(() => {
        loadClientJobs();
    }, []);

    // Check review status when completed jobs load
    useEffect(() => {
        if (jobs.completed.length > 0) {
            jobs.completed.forEach(job => {
                if (job.assigned_worker) {
                    checkIfReviewed(job.id, job.assigned_worker.id);
                }
            });
        }
    }, [jobs.completed]);

    const loadClientJobs = async () => {
        setLoading(true);
        try {
            const response = await api.get('/client/jobs');
            if (response.data.success) {
                const allJobs = response.data.data;

                setJobs({
                    posted: allJobs.filter(job => job.status === 'posted'),
                    assigned: allJobs.filter(job => job.status === 'assigned'),
                    in_progress: allJobs.filter(job => job.status === 'in_progress'),
                    completed: allJobs.filter(job => job.status === 'completed'),
                    cancelled: allJobs.filter(job => job.status === 'cancelled')
                });
            } else {
                setError('Failed to load jobs');
            }
        } catch (error) {
            console.error('Error loading client jobs:', error);
            setError('Network error. Please try again.');
        } finally {
            setLoading(false);
        }
    };

    const handleStartJob = async (jobId) => {
        if (!window.confirm('Start this job? The worker will be notified that work has begun.')) {
            return;
        }

        try {
            const response = await api.post(`/jobs/${jobId}/start`);
            if (response.data.success) {
                alert('✅ Job started! The worker has been notified.');
                loadClientJobs();
            }
        } catch (error) {
            console.error('Error starting job:', error);
            alert('Failed to start job. Please try again.');
        }
    };

    const handleCompleteClick = (job) => {
        setCurrentJobForRating(job);
        setShowRatingModal(true);
    };

    const handleCompleteJob = async () => {
        if (!currentJobForRating) return;

        console.log('='.repeat(50));
        console.log('🔵 COMPLETE JOB DEBUG:');
        console.log('Job object:', currentJobForRating);
        console.log('Job ID:', currentJobForRating.id);
        console.log('Job Status:', currentJobForRating.status);
        console.log('Rating:', ratingData.rating);
        console.log('Review:', ratingData.review);
        console.log('='.repeat(50));

        // Validate job ID
        if (!currentJobForRating.id) {
            console.error('❌ No job ID found');
            alert('Error: Job ID not found');
            return;
        }

        // Validate rating
        if (!ratingData.rating || ratingData.rating < 1 || ratingData.rating > 5) {
            alert('Please select a rating between 1 and 5 stars');
            return;
        }

        try {
            console.log(`📡 Sending POST request to: /jobs/${currentJobForRating.id}/complete`);

            const response = await api.post(`/jobs/${currentJobForRating.id}/complete`, {
                rating: ratingData.rating,
                review: ratingData.review
            });

            console.log('✅ Server response:', response.data);

            if (response.data.success) {
                // Safely handle the worker rating
                const workerRating = response.data.data?.worker_rating;

                // Format the rating safely
                let ratingDisplay = 'N/A';
                if (workerRating !== null && workerRating !== undefined) {
                    const numRating = Number(workerRating);
                    if (!isNaN(numRating)) {
                        ratingDisplay = numRating.toFixed(1);
                    }
                }

                alert(`✅ Job completed! Worker rating updated to ${ratingDisplay}⭐`);

                setShowRatingModal(false);
                setRatingData({ rating: 5, review: '' });
                setCurrentJobForRating(null);
                loadClientJobs(); // Refresh the jobs list
            }
        } catch (error) {
            console.error('❌ Error completing job:', error);
            console.error('❌ Error response:', error.response?.data);
            console.error('❌ Error status:', error.response?.status);

            const navigate = useNavigate();
            if (error.response?.status === 404) {
                alert(`Job #${currentJobForRating.id} not found. It may have been already completed or cancelled.`);
            } else if (error.response?.status === 400) {
                alert(error.response?.data?.message || 'Invalid request. Please check your rating.');
            } else if (error.response?.status === 401) {
                alert('Your session has expired. Please login again.');
                navigate('/login');
            } else if (error.response?.status === 403) {
                alert('You are not authorized to complete this job.');
            } else {
                alert(error.response?.data?.message || 'Failed to complete job. Please try again.');
            }
        }
    };

    const handleCancelJob = async (jobId) => {
        if (!window.confirm('Cancel this job? This cannot be undone.')) {
            return;
        }

        try {
            const response = await api.post(`/jobs/${jobId}/cancel`);
            if (response.data.success) {
                alert('Job cancelled.');
                loadClientJobs();
            }
        } catch (error) {
            console.error('Error cancelling job:', error);
            alert('Failed to cancel job. Please try again.');
        }
    };

    const handleReviewClick = (job) => {
        setCurrentJobForReview(job);
        setShowReviewModal(true);
    };

    const handleSubmitReview = async ({ jobId, rating, review, revieweeId }) => {
        try {
            const response = await api.post(`/jobs/${jobId}/review`, {
                rating,
                review,
                revieweeId
            });

            if (response.data.success) {
                alert('✅ Review submitted successfully!');
                setHasReviewed(prev => ({
                    ...prev,
                    [jobId]: true
                }));
                loadClientJobs();
            }
        } catch (error) {
            console.error('Error submitting review:', error);
            throw new Error(error.response?.data?.message || 'Failed to submit review');
        }
    };

    const checkIfReviewed = async (jobId, workerId) => {
        try {
            const response = await api.get(`/jobs/${jobId}/has-reviewed`);
            if (response.data.success) {
                setHasReviewed(prev => ({
                    ...prev,
                    [jobId]: response.data.hasReviewed
                }));
            }
        } catch (error) {
            console.error('Error checking review status:', error);
        }
    };

    const formatDate = (dateString) => {
        if (!dateString) return 'Unknown date';
        const date = new Date(dateString);
        return date.toLocaleDateString('en-ZA', {
            day: 'numeric',
            month: 'short',
            year: 'numeric'
        });
    };

    // SINGLE renderJobs function
    const renderJobs = (jobList, status) => {
        if (jobList.length === 0) {
            return (
                <div className="empty-state">
                    <p>No {status} jobs</p>
                    <Link to="/jobs/post" className="btn-primary">Post a Job</Link>
                </div>
            );
        }

        return jobList.map(job => (
            <div key={job.id} className={`job-card status-${job.status}`}>
                <div className="job-header">
                    <h3>{job.title || 'Untitled Job'}</h3>
                    <span className="job-status-badge">{job.status}</span>
                </div>

                <div className="job-details">
                    <p className="job-description">{job.description || 'No description'}</p>

                    <div className="job-meta">
                        <span>📍 {job.township || 'Location not specified'}</span>
                        <span>💰 R{job.budget_min || 0} - R{job.budget_max || 0}</span>
                        <span>📅 Posted {formatDate(job.created_at)}</span>
                    </div>

                    {job.assigned_worker && (
                        <div className="worker-info">
                            <h4>Worker:</h4>
                            <div className="worker-details">
                                <span className="worker-name">👤 {job.assigned_worker.name || 'Unknown'}</span>
                                <span className="worker-rating">
                                    ⭐ {formatRating(job.assigned_worker.rating)}
                                </span>
                                <span className="worker-phone">📱 {job.assigned_worker.phone || 'No phone'}</span>
                                <Link to={`/workers/${job.assigned_worker.id}`} className="worker-profile-link">
                                    View Profile →
                                </Link>
                            </div>
                        </div>
                    )}

                    <div className="job-actions">
                        <Link to={`/jobs/${job.id}`} className="btn-view">
                            View Details
                        </Link>

                        {job.status === 'assigned' && (
                            <>
                                <button 
                                    className="btn-start"
                                    onClick={() => handleStartJob(job.id)}
                                >
                                    ▶️ Start Job
                                </button>
                                <button 
                                    className="btn-cancel"
                                    onClick={() => handleCancelJob(job.id)}
                                >
                                    ✕ Cancel
                                </button>
                            </>
                        )}

                        {job.status === 'in_progress' && (
                            <>
                                <button 
                                    className="btn-complete"
                                    onClick={() => handleCompleteClick(job)}
                                >
                                    ✅ Complete Job
                                </button>
                                <button 
                                    className="btn-cancel"
                                    onClick={() => handleCancelJob(job.id)}
                                >
                                    ✕ Cancel
                                </button>
                            </>
                        )}

                        {job.status === 'completed' && (
                            <button 
                                className={`btn-review ${hasReviewed[job.id] ? 'reviewed' : ''}`}
                                onClick={() => handleReviewClick(job)}
                                disabled={hasReviewed[job.id]}
                            >
                                {hasReviewed[job.id] ? '⭐ Review Submitted' : '⭐ Leave Review'}
                            </button>
                        )}
                    </div>
                </div>
            </div>
        ));
    };

    if (loading) {
        return <div className="loading-spinner">Loading your jobs...</div>;
    }

    return (
        <div className="client-dashboard">
            <div className="dashboard-header">
                <h1>My Jobs Dashboard</h1>
                <Link to="/jobs/post" className="btn-primary">
                    + Post New Job
                </Link>
            </div>

            {error && <div className="error-message">{error}</div>}


            {/* Stats Navigation Cards */}
            <div className="stats-nav-grid">
                {/* To Start / Assigned */}
                <div 
                    className={`stat-nav-card assigned ${activeTab === 'assigned' ? 'active' : ''}`}
                    onClick={() => setActiveTab('assigned')}
                >
                    <div className="stat-nav-icon">▶️</div>
                    <div className="stat-nav-content">
                        <span className="stat-nav-value">{jobs.assigned.length}</span>
                        <span className="stat-nav-label">To Start</span>
                        <div className="stat-nav-progress">
                            <div 
                                className="stat-nav-progress-bar" 
                                style={{ width: `${calculateProgress('assigned')}%` }}
                            ></div>
                        </div>
                    </div>
                </div>

                {/* In Progress */}
                <div 
                    className={`stat-nav-card in_progress ${activeTab === 'in_progress' ? 'active' : ''}`}
                    onClick={() => setActiveTab('in_progress')}
                >
                    <div className="stat-nav-icon">⚙️</div>
                    <div className="stat-nav-content">
                        <span className="stat-nav-value">{jobs.in_progress.length}</span>
                        <span className="stat-nav-label">In Progress</span>
                        <div className="stat-nav-progress">
                            <div 
                                className="stat-nav-progress-bar" 
                                style={{ width: `${calculateProgress('assigned')}%` }}
                            ></div>
                        </div>
                    </div>
                </div>

                {/* Open / Posted */}
                <div 
                    className={`stat-nav-card posted ${activeTab === 'posted' ? 'active' : ''}`}
                    onClick={() => setActiveTab('posted')}
                >
                    <div className="stat-nav-icon">📋</div>
                    <div className="stat-nav-content">
                        <span className="stat-nav-value">{jobs.posted.length}</span>
                        <span className="stat-nav-label">Open</span>
                        <div className="stat-nav-progress">
                            <div 
                                className="stat-nav-progress-bar" 
                                style={{ width: `${calculateProgress('assigned')}%` }}
                            ></div>
                        </div>
                    </div>
                </div>

                {/* Completed */}
                <div 
                    className={`stat-nav-card completed ${activeTab === 'completed' ? 'active' : ''}`}
                    onClick={() => setActiveTab('completed')}
                >
                    <div className="stat-nav-icon">✅</div>
                    <div className="stat-nav-content">
                        <span className="stat-nav-value">{jobs.completed.length}</span>
                        <span className="stat-nav-label">Completed</span>
                        <div className="stat-nav-progress">
                            <div 
                                className="stat-nav-progress-bar" 
                                style={{ width: `${calculateProgress('assigned')}%` }}
                            ></div>
                        </div>
                    </div>
                </div>
            </div>


            {/* Jobs List */}
            <div className="jobs-list">
                {activeTab === 'assigned' && renderJobs(jobs.assigned, 'assigned')}
                {activeTab === 'in_progress' && renderJobs(jobs.in_progress, 'in progress')}
                {activeTab === 'posted' && renderJobs(jobs.posted, 'open')}
                {activeTab === 'completed' && renderJobs(jobs.completed, 'completed')}
            </div>

            {/* Rating Modal */}
            {showRatingModal && currentJobForRating && (
                <div className="modal-overlay">
                    <div className="rating-modal">
                        <h2>Rate the Worker</h2>
                        <p>How was {currentJobForRating.assigned_worker?.name || 'the worker'}'s work?</p>

                        <div className="rating-stars">
                            {[1, 2, 3, 4, 5].map(star => (
                                <button
                                    key={star}
                                    className={`star-btn ${ratingData.rating >= star ? 'active' : ''}`}
                                    onClick={() => setRatingData({...ratingData, rating: star})}
                                    type="button"
                                >
                                    ★
                                </button>
                            ))}
                        </div>

                        <div className="form-group">
                            <label>Review (Optional)</label>
                            <textarea
                                value={ratingData.review}
                                onChange={(e) => setRatingData({...ratingData, review: e.target.value})}
                                placeholder="Tell others about your experience..."
                                rows="3"
                            />
                        </div>

                        <div className="modal-actions">
                            <button 
                                className="btn-cancel"
                                type="button"
                                onClick={() => {
                                    setShowRatingModal(false);
                                    setRatingData({ rating: 5, review: '' });
                                    setCurrentJobForRating(null);
                                }}
                            >
                                Skip for now
                            </button>
                            <button 
                                className="btn-submit"
                                type="button"
                                onClick={handleCompleteJob}
                            >
                                Submit Rating & Complete
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {/* Review Modal */}
            <ReviewModal
                isOpen={showReviewModal}
                onClose={() => {
                    setShowReviewModal(false);
                    setCurrentJobForReview(null);
                }}
                onSubmit={handleSubmitReview}
                jobId={currentJobForReview?.id}
                revieweeId={currentJobForReview?.assigned_worker?.id}
                revieweeName={currentJobForReview?.assigned_worker?.name}
                hasReviewed={currentJobForReview ? hasReviewed[currentJobForReview.id] : false}
            />
        </div>
    );
};

export default ClientDashboard;
